class Solution {
public:
    bool canIWin(int maxChoosableInteger, int desiredTotal) {
        if (desiredTotal <= 0) return true;
        int sum = (1 + maxChoosableInteger) * maxChoosableInteger / 2;
        if (sum < desiredTotal) return false;
        if (sum == desiredTotal) return maxChoosableInteger % 2 == 1;
        vector<bool> memo(1 << maxChoosableInteger, false);
        return dfs(maxChoosableInteger, desiredTotal, 0, memo);
    }

    bool dfs(int maxChoosableInteger, int desiredTotal, int state, vector<bool>& memo) {
        if (memo[state]) return false;
        memo[state] = true;
        for (int i = 1; i <= maxChoosableInteger; i++) {
            if ((state >> (i - 1)) & 1) continue;
            if (i >= desiredTotal || !dfs(maxChoosableInteger, desiredTotal - i, state | (1 << (i - 1)), memo)) {
                return true;
            }
        }
        return false;
    }
};

